module top_module(in1,
            in2,
            obf_out,
            clk,
            rst);input [3:0]in1,in2;
    input rst,clk;

    output reg [4:0] obf_out;

    always@(posedge clk or posedge rst)
    begin
        if(rst==1)
        begin
            obf_out<=0;
        end
        else 
        begin
            obf_out<=in1+in2;    
        end
    end

endmodule
